import { useEffect, useState } from "react";
import { subscribeAgentActions } from "../services/firestore";

function formatTimestamp(timestamp) {
  if (!timestamp?.toDate) return "Pending";
  return timestamp.toDate().toLocaleString();
}

export default function AgentActionsFeed() {
  const [actions, setActions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const unsubscribe = subscribeAgentActions(
      (data) => {
        setActions(data);
        setLoading(false);
        setError("");
      },
      () => {
        setError("Unable to load agent actions.");
        setLoading(false);
      }
    );

    return unsubscribe;
  }, []);

  return (
    <section className="card p-6">
      <div className="mb-5">
        <h2 className="card-header">Agent Action Log</h2>
        <p className="card-subtext">Recent selections from the agent action panel.</p>
      </div>

      {loading ? (
        <p className="text-brand-slate">Loading actions...</p>
      ) : error ? (
        <p className="text-red-600 text-sm font-semibold">{error}</p>
      ) : actions.length === 0 ? (
        <p className="text-brand-slate">No agent actions logged yet.</p>
      ) : (
        <div className="space-y-3">
          {actions.map((action) => (
            <article key={action.id} className="border border-brand-border rounded-input p-4">
              <div className="flex items-start justify-between gap-4">
                <div>
                  <p className="font-extrabold text-brand-navy">{action.agentName || "Unknown Agent"}</p>
                  <p className="text-sm text-brand-slate mt-1">
                    Action: <span className="font-bold text-brand-navy">{action.actionType}</span>
                  </p>
                </div>
                <p className="text-sm text-brand-slate text-right shrink-0">
                  {formatTimestamp(action.timestamp)}
                </p>
              </div>
            </article>
          ))}
        </div>
      )}
    </section>
  );
}
